import axios from 'axios';

// Get all schemes
const getSchemes = async () => {
  const response = await axios.get('/api/schemes');
  return response.data;
};

// Get scheme by ID
const getSchemeById = async (schemeId) => {
  const response = await axios.get(`/api/schemes/${schemeId}`);
  return response.data;
};

// Search schemes
const searchSchemes = async (query) => {
  const response = await axios.get(`/api/schemes/search?query=${query}`);
  return response.data;
};

// Create a new scheme (admin only)
const createScheme = async (schemeData, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.post('/api/schemes', schemeData, config);
  return response.data;
};

// Update a scheme (admin only)
const updateScheme = async (schemeId, schemeData, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.put(`/api/schemes/${schemeId}`, schemeData, config);
  return response.data;
};

// Delete a scheme (admin only)
const deleteScheme = async (schemeId, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.delete(`/api/schemes/${schemeId}`, config);
  return response.data;
};

const schemeService = {
  getSchemes,
  getSchemeById,
  searchSchemes,
  createScheme,
  updateScheme,
  deleteScheme,
};

export default schemeService;
